#!/usr/bin/env node
'use strict';

const { pluginNamePattern } = require('./src/constants');

// Test cases
const testCases = [
  { id: 'nodebb-plugin-imgur', valid: true },
  { id: 'nodebb-plugin-test-name', valid: true },
  { id: '@scope/nodebb-plugin-custom', valid: true },
  { id: '@nodebb/nodebb-plugin-abc', valid: true },
  { id: 'nodebb-theme-test', valid: true },
  { id: 'nodebb-widget-custom', valid: true },
  { id: 'nodebb-rewards-test', valid: true },

  // Invalid cases
  { id: '\t\nnodebb-plugin', valid: false }, // Whitespace
  { id: 'notaplugin', valid: false }, // No nodebb- prefix
  { id: 'nodebb-invalid-type', valid: false }, // Invalid type
  { id: 'nodebb-plugin ', valid: false }, // Trailing space
  { id: ' nodebb-plugin-test', valid: false }, // Leading space
];

console.log('Testing plugin name pattern validation:\n');

let passed = 0;
let failed = 0;

testCases.forEach(test => {
  const result = pluginNamePattern.test(test.id);
  const status = result === test.valid ? '✓ PASS' : '✗ FAIL';

  if (result === test.valid) {
    passed++;
  } else {
    failed++;
  }

  console.log(`${status}: "${test.id}" - Expected valid=${test.valid}, Got ${result}`);
});

console.log(`\n${passed} passed, ${failed} failed`);

if (failed > 0) {
  process.exit(1);
}

#!/usr/bin/env node
'use strict';

const { pluginNamePattern } = require('./src/constants');
const assert = require('assert');

console.log('='.repeat(60));
console.log('Verifying Plugin ID Validation Implementation');
console.log('='.repeat(60));

// Test 1: Pattern exists
console.log('\n[TEST 1] Pattern definition exists');
try {
  assert(pluginNamePattern instanceof RegExp, 'pluginNamePattern should be a RegExp');
  console.log('✓ pluginNamePattern is a RegExp');
} catch (err) {
  console.log('✗ FAILED:', err.message);
  process.exit(1);
}

// Test 2: Pattern format
console.log('\n[TEST 2] Pattern format verification');
const patternStr = pluginNamePattern.toString();
console.log('Pattern:', patternStr);
const expectedKeywords = ['nodebb', 'theme', 'plugin', 'widget', 'rewards'];
expectedKeywords.forEach(keyword => {
  if (patternStr.includes(keyword)) {
    console.log(`✓ Pattern includes "${keyword}"`);
  } else {
    console.log(`✗ Pattern does NOT include "${keyword}"`);
    process.exit(1);
  }
});

// Test 3: Valid plugin IDs
console.log('\n[TEST 3] Valid plugin IDs should match pattern');
const validIds = [
  'nodebb-plugin-imgur',
  'nodebb-plugin-markdown',
  'nodebb-theme-persona',
  'nodebb-widget-essentials',
  'nodebb-rewards-essentials',
  '@nodebb/nodebb-plugin-abc',
  '@scope/nodebb-plugin-custom',
];
validIds.forEach(id => {
  if (pluginNamePattern.test(id)) {
    console.log(`✓ "${id}" is valid`);
  } else {
    console.log(`✗ "${id}" should be valid but isn't`);
    process.exit(1);
  }
});

// Test 4: Invalid plugin IDs
console.log('\n[TEST 4] Invalid plugin IDs should NOT match pattern');
const invalidIds = [
  '\t\nnodebb-plugin',  // Whitespace
  'notaplugin',        // No nodebb- prefix
  'nodebb-invalid-name', // Invalid type
  'nodebb-plugin ',    // Trailing space
  ' nodebb-plugin-test', // Leading space
  'nbb-plugin-test',   // Wrong prefix
];
invalidIds.forEach(id => {
  if (!pluginNamePattern.test(id)) {
    console.log(`✓ "${id.replace(/\n/g, '\\n')}" is correctly rejected`);
  } else {
    console.log(`✗ "${id.replace(/\n/g, '\\n')}" should be invalid but isn't`);
    process.exit(1);
  }
});

// Test 5: Check install.js has the validation
console.log('\n[TEST 5] Checking install.js implementation');
const fs = require('fs');
const installJs = fs.readFileSync('./src/plugins/install.js', 'utf-8');
if (installJs.includes('pluginNamePattern')) {
  console.log('✓ install.js imports pluginNamePattern');
} else {
  console.log('✗ install.js does NOT import pluginNamePattern');
  process.exit(1);
}

if (installJs.includes("!pluginNamePattern.test(id)")) {
  console.log('✓ install.js has validation check for pattern');
} else {
  console.log('✗ install.js does NOT have validation check');
  process.exit(1);
}

if (installJs.includes("'[[error:invalid-plugin-id]]'")) {
  console.log('✓ install.js throws correct error message');
} else {
  console.log('✗ install.js does NOT throw correct error message');
  process.exit(1);
}

// Test 6: Check test file has the validation test
console.log('\n[TEST 6] Checking test/plugins.js has validation test');
const testJs = fs.readFileSync('./test/plugins.js', 'utf-8');
if (testJs.includes('should error if plugin id is invalid')) {
  console.log('✓ test/plugins.js has validation test');
} else {
  console.log('✗ test/plugins.js does NOT have validation test');
  process.exit(1);
}

if (testJs.includes('\t\nnodebb-plugin')) {
  console.log('✓ test includes whitespace test case');
} else {
  console.log('✗ test does NOT include whitespace test case');
  process.exit(1);
}

if (testJs.includes('notaplugin')) {
  console.log('✓ test includes invalid plugin name test case');
} else {
  console.log('✗ test does NOT include invalid plugin name test case');
  process.exit(1);
}

console.log('\n' + '='.repeat(60));
console.log('✓ ALL VERIFICATION TESTS PASSED!');
console.log('='.repeat(60));

