261: Plugins.showInstalled = async function () {
262: 	const dirs = await fs.promises.readdir(Plugins.nodeModulesPath);
263: 
264: 	let pluginPaths = await findNodeBBModules(dirs);
265: 	pluginPaths = pluginPaths.map(dir => path.join(Plugins.nodeModulesPath, dir));
266: 
267: 	async function load(file) {
268: 		try {
269: 			const pluginData = await Plugins.loadPluginInfo(file);
270: 			const isActive = await Plugins.isActive(pluginData.name);
271: 			delete pluginData.hooks;
272: 			delete pluginData.library;
273: 			pluginData.active = isActive;
274: 			pluginData.installed = true;
275: 			pluginData.error = false;
276: 			return pluginData;
277: 		} catch (err) {
278: 			winston.error(err.stack);
279: 		}
280: 	}
281: 	const plugins = await Promise.all(pluginPaths.map(file => load(file)));
282: 	return plugins.filter(Boolean);
283: };
